import axios from 'axios';

const BACKEND_URL = process.env.REACT_APP_API_URL || '';

interface PassAuthUrlResponse {
    code: string;
    message: string;
    timestamp: string;
    requestNo: string;
    authUrl: string;
    expiresIn: number;
}

// requestNo 생성 (20~50byte 고유 ID)
export const generateRequestNo = (): string => {
    const timestamp = Date.now().toString(36);
    const random = Math.random().toString(36).substring(2, 12);
    return `${timestamp}_${random}`;
};

// PASS 인증 URL 발급 (백엔드 프록시 경유)
export const getPassAuthUrl = async (requestNo: string, closeUrl?: string): Promise<PassAuthUrlResponse> => {
    const response = await axios.post<PassAuthUrlResponse>(
        `${BACKEND_URL}/api/front/common/pass/auth-url`,
        {
            requestNo,
            closeUrl,
            expMods: ['closeButtonOn'],
        }
    );

    if (response.data.code !== '200') {
        throw new Error(response.data.message || 'PASS 인증 URL 발급 실패');
    }

    return response.data;
};

// 핸드폰 번호 중복 확인 (true = 이미 가입된 번호)
export const validatePhone = async (phone: string): Promise<boolean> => {
    const baseUrl = window.location.origin;
    const response = await axios.get(`${baseUrl}/api/front/auth/validate-phone`, { params: { phone } });
    return response.data.data;
};

// NICE 인증 결과 조회 (콜백 후 resultKey로 결과 획득)
// 콜백 후 현재 도메인 기준으로 호출 (로컬 IP 문제 방지)
export const getPassAuthResult = async (resultKey: string): Promise<any> => {
    const baseUrl = window.location.origin;
    const response = await axios.get(
        `${baseUrl}/api/front/nice/result`,
        { params: { resultKey } }
    );
    return response.data;
};
